const __pageData = JSON.parse('{"title":"命令式范式：状态与控制的本质","description":"深入剖析命令式编程的形式化基础——从冯·诺依曼架构到存储程序概念，从赋值语义到结构化定理，并映射到 JavaScript 引擎优化与系统编程的工程实践。","frontmatter":{"title":"命令式范式：状态与控制的本质","description":"深入剖析命令式编程的形式化基础——从冯·诺依曼架构到存储程序概念，从赋值语义到结构化定理，并映射到 JavaScript 引擎优化与系统编程的工程实践。","date":"2026-05-01T00:00:00.000Z","tags":["编程范式","命令式编程","计算机体系结构","V8 引擎","性能优化"],"category":"theoretical-foundations"},"headers":[],"relativePath":"programming-paradigms/02-imperative-paradigm.md","filePath":"programming-paradigms/02-imperative-paradigm.md","lastUpdated":1777712107000}');
